import { useState, useEffect, useRef } from "react";

/* ─────────────────────────────────────────
   DESIGN TOKENS — Modern Gold & Deep Theme
───────────────────────────────────────── */
const C = {
  // Backgrounds - deeper and more premium
  bgDeep:    "#03050A",
  bgBase:    "#080C14",
  bgSurface: "#0F1622",
  bgCard:    "#121A2A",
  
  // Brand Gold (Sri Lanka identity)
  gold:      "#E5B13B",
  goldLight: "#F5CD6D",
  goldTint:  "#E5B13B1A",
  borderGold:"#E5B13B33",
  
  // Crimson accent
  red:       "#C73B2A",
  redLight:  "#E55B48",
  
  // Status colors
  kept:      "#16A34A",
  keptLight: "#22C55E",
  keptTint:  "#16A34A18",
  broken:    "#DC2626",
  brokenTint:"#DC262618",
  pending:   "#F59E0B",
  pendingTint:"#F59E0B18",
  
  // Text
  text1: "#F1F5F9",
  text2: "#8CA3C0",
  text3: "#4A5B7A",
  
  // Borders
  border: "#1F2A44",
  
  // Nav overlay
  navBg: "#03050AEE",
  
  // Accent
  accent: "#3B82F6",
  accentTint: "#3B82F618",
};

/* ─────────────────────────────────────────
   DATA - Updated with promise tracking
───────────────────────────────────────── */
const politicians = [
  { name: "Ranil Wickremesinghe", role: "President · UNP", emoji: "🧑‍💼", score: 62, kept: 12, broken: 8, pending: 6, scoreColor: C.gold },
  { name: "Sajith Premadasa", role: "Opposition Leader · SJB", emoji: "👨‍💼", score: 78, kept: 19, broken: 4, pending: 3, scoreColor: C.keptLight },
  { name: "Mahinda Rajapaksa", role: "MP · SLPP · Southern", emoji: "🧓", score: 34, kept: 6, broken: 14, pending: 2, scoreColor: C.redLight },
  { name: "Harini Amarasuriya", role: "Prime Minister · NPP", emoji: "👩‍💼", score: 81, kept: 9, broken: 1, pending: 7, scoreColor: C.keptLight },
];

const promises = [
  { id: 1, title: "Reduce electricity tariff by 25% in Western Province", status: "progress", politician: "Anura K.", district: "Colombo", confidence: 68, votes: 234 },
  { id: 2, title: "Build 5,000 new affordable housing units in Galle", status: "kept", politician: "M. Silva", district: "Galle", confidence: 94, votes: 1245 },
  { id: 3, title: "Free public university education expansion by 2025", status: "broken", politician: "R. Premadasa", district: "National", confidence: 12, votes: 789 },
  { id: 4, title: "New water supply project for rural areas", status: "kept", politician: "S. Wickrama", district: "Kandy", confidence: 89, votes: 567 },
];

const features = [
  { icon: "📋", title: "Promise Tracker", desc: "Every election promise logged, categorized, and verified with real evidence and trusted sources.", api: "GET /api/promises" },
  { icon: "📊", title: "Performance Scores", desc: "Transparent scores based on promise fulfillment, voting record, and community feedback.", api: "GET /api/promises/stats" },
  { icon: "🗳️", title: "Voting Records", desc: "Every parliamentary vote publicly accessible. See exactly how your MP voted.", api: "GET /api/politicians/:id" },
  { icon: "💰", title: "Spending Watch", desc: "Track declared assets, public expenditures, and financial disclosures.", api: "GET /api/politicians" },
  { icon: "🔔", title: "Citizen Alerts", desc: "Get notified when promises are updated or new records are filed.", api: "POST /api/notifications/subscribe" },
  { icon: "🤝", title: "Community Reports", desc: "Citizens can submit evidence and upvote truthfulness.", api: "POST /api/feedback/:promiseId/vote" },
];

const newsItems = [
  { title: "New rural development fund announced - matching promise ID #PR-204", time: "2h ago", linked: true, source: "Daily Mirror" },
  { title: "Opposition leader comments on tariff reduction plan", time: "Yesterday", linked: false, source: "NewsFirst" },
  { title: "Election commission releases candidate pledge tracker", time: "3d ago", linked: true, source: "Ada Derana" },
];

const trendingTopics = [
  { tag: "#WelfareBudget2026", posts: "12.5k posts", color: C.gold },
  { tag: "#ColomboDistrictPromises", posts: "8.2k posts", color: C.accent },
  { tag: "#AccountabilityLK", posts: "5.7k posts", color: C.redLight },
];

const comments = [
  { id: 1, user: "Piumi Silva", avatar: "PS", time: "2 hours ago", content: "The new water supply project was inaugurated last week, promise fulfilled! Attached news report as evidence.", likes: 24, dislikes: 2, hasEvidence: true },
  { id: 2, user: "M. Kariyawasam", avatar: "MK", time: "Yesterday", content: "No progress on rural road development despite multiple promises. I've added geotagged photos as feedback.", likes: 58, dislikes: 3, hasEvidence: true },
];

const notifications = [
  { id: 1, type: 'promise', title: 'Promise status updated', description: 'Rural electrification project marked as "Completed"', time: '5 min ago', unread: true },
  { id: 2, type: 'evidence', title: 'New evidence submitted', description: 'Citizen uploaded photos for water supply promise', time: '1 hour ago', unread: true },
  { id: 3, type: 'alert', title: 'District update', description: 'New promises added for Colombo District', time: '3 hours ago', unread: false },
];

const tickerItems = [
  { label: "KEPT", bg: C.keptTint, color: C.keptLight, text: "Education budget increased 15% — Ministry of Finance" },
  { label: "BROKEN", bg: C.brokenTint, color: C.redLight, text: "10,000 housing units pledge — 2 years overdue" },
  { label: "PENDING", bg: C.pendingTint, color: C.pending, text: "Anti-corruption bill — Committee review ongoing" },
  { label: "KEPT", bg: C.keptTint, color: C.keptLight, text: "Free school meals program — Fully implemented" },
];

/* ─────────────────────────────────────────
   COUNT-UP HOOK
───────────────────────────────────────── */
function useCountUp(target, duration = 1400, trigger = false) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!trigger) return;
    let t0 = null;
    const step = (ts) => {
      if (!t0) t0 = ts;
      const p = Math.min((ts - t0) / duration, 1);
      setVal(Math.floor(p * target));
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [trigger, target, duration]);
  return val;
}

/* ─────────────────────────────────────────
   STAT ITEM
───────────────────────────────────────── */
function StatItem({ raw, suffix = "", label }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  const num = useCountUp(raw, 1400, vis);
  useEffect(() => {
    const ob = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold: 0.4 });
    if (ref.current) ob.observe(ref.current);
    return () => ob.disconnect();
  }, []);
  const display = raw >= 1000 ? num.toLocaleString() : num;

  return (
    <div ref={ref}
      style={{ background: C.bgBase, padding: "3rem 1.5rem", display: "flex", flexDirection: "column", alignItems: "center", cursor: "default", transition: "background .25s", borderRight: `1px solid ${C.border}` }}
      onMouseEnter={e => e.currentTarget.style.background = C.bgSurface}
      onMouseLeave={e => e.currentTarget.style.background = C.bgBase}
    >
      <span style={{ fontFamily: "'Space Mono',monospace", fontSize: "2.8rem", fontWeight: 900, color: C.gold, lineHeight: 1, marginBottom: "0.5rem" }}>
        {display}{suffix}
      </span>
      <p style={{ fontSize: "0.78rem", color: C.text2, textAlign: "center", lineHeight: 1.6, maxWidth: 130 }}>{label}</p>
    </div>
  );
}

/* ─────────────────────────────────────────
   HELPERS
───────────────────────────────────────── */
function SectionLabel({ text }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: "0.7rem", fontSize: "0.72rem", fontWeight: 700, letterSpacing: "0.15em", textTransform: "uppercase", color: C.gold, fontFamily: "'Space Mono',monospace", marginBottom: "1rem" }}>
      <span style={{ width: 22, height: 2, background: C.gold, display: "inline-block" }} />
      {text}
    </div>
  );
}

function Tag({ bg, color, border, children }) {
  return (
    <span style={{ fontSize: "0.65rem", padding: "0.2rem 0.55rem", borderRadius: "4px", fontWeight: 700, background: bg, color: color, border: `1px solid ${border}` }}>
      {children}
    </span>
  );
}

function StatusBadge({ status }) {
  const config = {
    kept: { bg: C.keptTint, color: C.keptLight, text: "✅ Kept" },
    progress: { bg: C.pendingTint, color: C.pending, text: "⏳ In Progress" },
    broken: { bg: C.brokenTint, color: C.redLight, text: "❌ Broken" },
  };
  const s = config[status] || config.progress;
  return <Tag bg={s.bg} color={s.color} border={`${s.color}40`}>{s.text}</Tag>;
}

/* ─────────────────────────────────────────
   MAIN COMPONENT
───────────────────────────────────────── */
export default function PledgeTrack() {
  const [search, setSearch] = useState("");
  const [scrolled, setScrolled] = useState(false);
  const [selectedStatus, setSelectedStatus] = useState("all");

  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  const filteredPromises = selectedStatus === "all" 
    ? promises 
    : promises.filter(p => p.status === selectedStatus);

  return (
    <div style={{ minHeight: "100vh", background: C.bgBase, color: C.text1, fontFamily: "'Sora',sans-serif", overflowX: "hidden" }}>

      {/* ── GLOBAL CSS ── */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;600;700;800;900&family=Space+Mono:wght@400;700&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        ::-webkit-scrollbar { width: 5px; }
        ::-webkit-scrollbar-track { background: ${C.bgDeep}; }
        ::-webkit-scrollbar-thumb { background: ${C.gold}; border-radius: 3px; }

        @keyframes ticker { from { transform: translateX(0); } to { transform: translateX(-50%); } }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(28px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes glowDot { 0%,100% { opacity: 1; transform: scale(1); } 50% { opacity: .45; transform: scale(.65); } }
        @keyframes pulseGlow { 0%,100% { box-shadow: 0 0 0 0 ${C.gold}44; } 50% { box-shadow: 0 0 0 6px transparent; } }

        .ticker-run { animation: ticker 38s linear infinite; white-space: nowrap; }
        .fade0 { animation: fadeUp .7s ease both; }
        .fade1 { animation: fadeUp .7s .13s ease both; }
        .fade2 { animation: fadeUp .7s .26s ease both; }
        .fade3 { animation: fadeUp .7s .4s ease both; }
        .glow { animation: glowDot 2s ease infinite; }
        .pulse-glow { animation: pulseGlow 2s ease infinite; }

        .grid-bg {
          background-image: linear-gradient(${C.gold}09 1px, transparent 1px), linear-gradient(90deg, ${C.gold}09 1px, transparent 1px);
          background-size: 58px 58px;
        }

        .card-hover { transition: transform .28s, border-color .28s, box-shadow .28s !important; }
        .card-hover:hover { transform: translateY(-5px) !important; border-color: ${C.gold}66 !important; box-shadow: 0 20px 48px ${C.bgDeep}BB !important; }

        .btn-gold-h:hover { background: ${C.goldLight} !important; transform: translateY(-2px) !important; box-shadow: 0 10px 28px ${C.gold}44 !important; }
        .btn-out-h:hover { border-color: ${C.gold} !important; color: ${C.gold} !important; transform: translateY(-2px) !important; }
        .nav-lnk:hover { color: ${C.gold} !important; }
        .search-in:focus { border-color: ${C.gold} !important; }

        @media(max-width: 1080px) {
          .rg-hero { grid-template-columns: 1fr !important; }
          .mock-col { display: none !important; }
          .rg-4 { grid-template-columns: 1fr 1fr !important; }
        }
        @media(max-width: 600px) {
          .rg-4 { grid-template-columns: 1fr !important; }
          .rg-3 { grid-template-columns: 1fr !important; }
          .nav-menu { display: none !important; }
          .sec { padding-left: 1.25rem !important; padding-right: 1.25rem !important; }
          .footer-r { flex-direction: column !important; gap: 1.5rem !important; text-align: center !important; }
        }
      `}</style>

